# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

from flask import Flask, request, session

app = Flask(__name__)

@app.route('/update-profile', methods=['POST'])
def update_profile():
    # Get the user's current session data
    user_data = session.get('user')

    # Update the user's email address
    if request.form.get('email'):
        user_data['email'] = request.form.get('email')

    # Update the user's password
    if request.form.get('password'):
        user_data['password'] = request.form.get('password')

    # Update the user's 2FA settings
    if request.form.get('twoFactorAuth'):
        user_data['twoFactorAuth'] = request.form.get('twoFactorAuth')

    # Save the updated session data
    session['user'] = user_data

    return 'Profile updated successfully!'